"use client";

import { useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { useGSAP } from "@gsap/react";
import { ArrowDownRight, ArrowUpRight } from "lucide-react";

gsap.registerPlugin(ScrollTrigger);

export default function Hero() {
    const containerRef = useRef<HTMLDivElement>(null);

    useGSAP(() => {
        // Elegant blur + slide in startup animation for main text
        gsap.from(".hero-char", {
            y: 100,
            opacity: 0,
            filter: "blur(20px)",
            duration: 1.5,
            stagger: 0.05,
            ease: "power4.out",
            delay: 2 // Wait for preloader
        });

        // Bottom section reveals
        gsap.from(".hero-bottom-element", {
            y: 40,
            opacity: 0,
            filter: "blur(10px)",
            duration: 1.2,
            stagger: 0.1,
            ease: "power3.out",
            delay: 2.8
        });

        // Scroll-out blur and parallax
        gsap.to(containerRef.current, {
            scrollTrigger: {
                trigger: containerRef.current,
                start: "top top",
                end: "bottom top",
                scrub: true,
            },
            opacity: 0,
            filter: "blur(30px)",
            y: -50,
            ease: "none"
        });

    }, { scope: containerRef });

    const title = "RANDIL FERNANDO";

    return (
        <section
            ref={containerRef}
            className="relative min-h-screen w-full flex flex-col justify-center overflow-hidden bg-[#EAE8E3] z-10 pt-32 pb-12"
        >
            {/* Huge Single Line Text */}
            <div className="w-full flex justify-center mb-12 md:mb-16 px-4 md:px-0">
                <h1 className="flex whitespace-nowrap text-[13vw] font-heading font-black leading-none tracking-tighter uppercase text-[#1A1A1A]">
                    {title.split("").map((char, index) => (
                        <span
                            key={index}
                            className="hero-char inline-block"
                            style={{ width: char === " " ? "0.3em" : "auto" }}
                        >
                            {char}
                        </span>
                    ))}
                </h1>
            </div>

            {/* Decorative Bottom Tri-Column Layout */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-12 md:gap-4 w-full px-6 md:px-12 items-end">

                {/* Left Column: Subtitle & Button */}
                <div className="hero-bottom-element flex flex-col items-start max-w-sm">
                    <ArrowDownRight size={32} strokeWidth={1.5} className="mb-6 text-[#1A1A1A]" />
                    <p className="text-lg md:text-xl text-[#333333] font-sans font-medium leading-relaxed mb-8">
                        Full-Stack Developer, Robotics Lead & Public Speaker. Building the future at the intersection of Hardware, AI, and Cloud Infrastructure.
                    </p>
                    <a href="mailto:hello@randilfernando.com" className="flex items-center gap-2 bg-[#1A1A1A] text-white px-8 py-4 rounded-full font-sans font-bold text-sm tracking-widest uppercase hover:bg-[#333] transition-colors hover-target cursor-none shadow-xl">
                        CONTACT <ArrowUpRight size={18} strokeWidth={2} />
                    </a>
                </div>

                {/* Center Column: Portrait Image */}
                <div className="hero-bottom-element flex justify-center w-full">
                    <div className="w-full max-w-[400px] aspect-[4/5] bg-[#DCD9D4] rounded-xl overflow-hidden shadow-2xl relative hover-view cursor-none">
                        {/* Fallback pattern */}
                        <div className="absolute inset-0 bg-gradient-to-tr from-[#CCCCCC] to-[#EAE8E3]"></div>
                        <img
                            src="/images/portrait.jpg"
                            alt="Randil Fernando - Portrait Portfolio"
                            className="absolute inset-0 w-full h-full object-cover mix-blend-multiply opacity-80 transition-transform duration-700 hover:scale-105"
                            onError={(e) => { e.currentTarget.style.display = 'none'; }}
                        />
                    </div>
                </div>

                {/* Right Column: Date / Availability */}
                <div className="hero-bottom-element flex flex-col md:items-end text-left md:text-right w-full">
                    <p className="text-[#666] font-sans font-bold tracking-widest text-sm uppercase mb-2">AVAILABLE FOR WORK</p>
                    <div className="text-[15vw] md:text-[8vw] font-heading font-black leading-none tracking-tighter text-[#1A1A1A]">
                        MAR'26
                    </div>
                </div>

            </div>
        </section>
    );
}

"use client";

import { useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { useGSAP } from "@gsap/react";

gsap.registerPlugin(ScrollTrigger);

const projects = [
    { id: 1, title: "BEAN", subtitle: "AI Keychain Therapeutic Robot", desc: "Physics-based Emotion Engine. Built with C++, ESP32 S3.", img: "bean-robot" },
    { id: 2, title: "EV from Scratch", subtitle: "Electric Vehicle Engineering", desc: "Power distribution, motor control, chassis integration.", img: "ev-project" },
    { id: 3, title: "Cloud-Native CI/CD", subtitle: "DevOps & Observability", desc: "Automated containerized deployments using Jenkins & GitHub.", img: "cicd-pipeline" },
    { id: 4, title: "4Rent.lk", subtitle: "Go Microservice Gateway", desc: "Integrated with WSO2 Asgardeo for enterprise authentication.", img: "4rent" },
    { id: 5, title: "Motion Relief", subtitle: "Android Mobile App", desc: "Dynamic visual overlays to reduce motion sickness (Kotlin).", img: "motion-relief" },
    { id: 6, title: "SQRL Budget", subtitle: "Expense Tracker", desc: "Open-source Kotlin application for analytics and local storage.", img: "sqrl" },
    { id: 7, title: "Pixel Scholar", subtitle: "Interactive Learning", desc: "A creative platform dedicated to interactive coding education.", img: "pixel-scholar" },
    { id: 8, title: "DevNeko", subtitle: "Tech Startup", desc: "Founder of high-performance mobile and web application development agency.", img: "devneko" }
];

export default function HorizontalScroll() {
    const containerRef = useRef<HTMLDivElement>(null);
    const scrollRef = useRef<HTMLDivElement>(null);

    useGSAP(() => {
        const sections = gsap.utils.toArray(".horizontal-item") as HTMLElement[];

        const tl = gsap.timeline({
            scrollTrigger: {
                trigger: containerRef.current,
                pin: true,
                scrub: 1,
                snap: 1 / (sections.length - 1),
                end: () => "+=" + scrollRef.current?.offsetWidth,
            }
        });

        tl.to(sections, {
            xPercent: -100 * (sections.length - 1),
            ease: "none",
        });

        // Parallax images
        sections.forEach((section) => {
            const img = section.querySelector("img");
            if (img) {
                gsap.to(img, {
                    xPercent: 30,
                    ease: "none",
                    scrollTrigger: {
                        trigger: section,
                        containerAnimation: tl,
                        start: "left right",
                        end: "right left",
                        scrub: true,
                    }
                });
            }
        });

        // Scroll out blur
        gsap.to(containerRef.current, {
            scrollTrigger: {
                trigger: containerRef.current,
                start: "bottom top+=200",
                end: "bottom top",
                scrub: true,
            },
            filter: "blur(20px)",
            opacity: 0,
        });
    }, { scope: containerRef });

    return (
        <section ref={containerRef} className="relative h-screen flex items-center bg-[#EAE8E3] overflow-hidden z-20">
            <div className="absolute top-12 left-12 z-10 text-[#1A1A1A]">
                <h2 className="text-sm font-sans tracking-widest text-[#666] uppercase">SELECTED WORKS /</h2>
            </div>

            <div ref={scrollRef} className="flex h-full w-[800vw]">
                {projects.map((project) => (
                    <div
                        key={project.id}
                        className="horizontal-item w-screen h-full flex items-center justify-center p-12 md:p-24"
                    >
                        <div className="relative w-full max-w-7xl h-[70vh] flex flex-col md:flex-row items-center gap-12 group hover-view cursor-none">

                            <div className="w-full md:w-[60%] h-[50vh] md:h-full relative overflow-hidden rounded-2xl bg-[#DCD9D4]">
                                <div className="absolute inset-0 bg-gradient-to-tr from-[#CCCCCC] to-[#EAE8E3]"></div>

                                <img
                                    src={`/images/${project.img}.jpg`}
                                    alt={`Randil Fernando - ${project.title} Portfolio`}
                                    className="absolute top-0 left-[-15%] w-[130%] h-full object-cover mix-blend-multiply opacity-50 transition-opacity duration-700 group-hover:opacity-80"
                                    onError={(e) => { e.currentTarget.style.display = 'none'; }}
                                />
                            </div>

                            <div className="w-full md:w-[40%] flex flex-col justify-center">
                                <span className="text-sm font-sans tracking-widest text-[#888] mb-4">0{project.id}</span>
                                <h3 className="text-4xl md:text-6xl lg:text-8xl font-heading font-black tracking-tighter mb-4 text-[#1A1A1A] leading-none transition-transform duration-700 group-hover:translate-x-4">
                                    {project.title}
                                </h3>
                                <h4 className="text-xl md:text-2xl font-sans text-[#444] font-bold mb-4">{project.subtitle}</h4>
                                <p className="text-[#666] text-lg font-sans font-medium">{project.desc}</p>
                            </div>

                        </div>
                    </div>
                ))}
            </div>
        </section>
    );
}

"use client";

import { useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { useGSAP } from "@gsap/react";

gsap.registerPlugin(ScrollTrigger);

export default function Neurobloom() {
    const containerRef = useRef<HTMLDivElement>(null);

    useGSAP(() => {
        gsap.from(".neuro-element", {
            scrollTrigger: {
                trigger: containerRef.current,
                start: "top 70%",
            },
            y: 100,
            opacity: 0,
            duration: 1,
            stagger: 0.1,
            ease: "power4.out",
        });

        gsap.to(containerRef.current, {
            scrollTrigger: {
                trigger: containerRef.current,
                start: "bottom top+=200",
                end: "bottom top",
                scrub: true,
            },
            filter: "blur(20px)",
            opacity: 0,
        });
    }, { scope: containerRef });

    return (
        <section ref={containerRef} className="py-32 px-6 md:px-24 bg-[#050505] text-[#EAE8E3] min-h-screen flex flex-col justify-center overflow-hidden z-20">
            <div className="max-w-6xl mx-auto w-full">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-16 neuro-element">
                    <div>
                        <h2 className="text-sm font-sans tracking-widest text-[#888] uppercase mb-4">STARTUP / ROBOTICS</h2>
                        <h3 className="text-5xl md:text-8xl font-heading font-black uppercase tracking-tighter leading-none text-white">
                            Neurobloom
                        </h3>
                    </div>
                    <p className="text-xl md:text-2xl text-[#888] font-sans max-w-md mt-6 md:mt-0 font-medium leading-relaxed">
                        Building the next generation of autonomous robotic systems.
                    </p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-12 gap-6 h-auto md:h-[600px]">
                    <div className="neuro-element md:col-span-8 bg-[#111] border border-[#222] rounded-3xl overflow-hidden relative group min-h-[400px]">
                        <img
                            src="/images/bean-robot.jpg"
                            alt="Randil Fernando - Neurobloom Robot Portfolio"
                            className="absolute inset-0 w-full h-full object-cover mix-blend-luminosity opacity-40 group-hover:opacity-80 transition-opacity duration-700"
                            onError={(e) => { e.currentTarget.style.display = 'none'; }}
                        />
                        <div className="absolute inset-0 flex items-center justify-center font-heading text-2xl md:text-4xl text-[#AAA] font-bold tracking-tighter uppercase transition-transform duration-700 group-hover:scale-105 text-center px-4 hover-view cursor-none z-10 pointer-events-none">
                            Primary Robot Visual
                        </div>
                        <div className="absolute top-8 right-8 bg-[#EAE8E3] text-black font-sans font-bold py-2 px-6 rounded-full rotate-[-12deg] shadow-xl text-sm md:text-base hover-target z-20">
                            v2.0 LIVE
                        </div>
                    </div>

                    <div className="neuro-element md:col-span-4 flex flex-col gap-6 min-h-[400px]">
                        <div className="flex-1 bg-[#111] border border-[#222] rounded-3xl overflow-hidden relative group">
                            <div className="absolute inset-0 flex items-center justify-center font-heading text-xl text-[#EAE8E3] font-bold text-center p-8 transition-transform duration-700 group-hover:scale-105 hover-view cursor-none z-10">
                                Hardware Specs / Banner
                            </div>
                        </div>
                        <div className="flex-[0.8] bg-[#EAE8E3] text-[#1A1A1A] border border-[#111] rounded-3xl overflow-hidden relative group p-8 flex flex-col justify-between hover-target z-10">
                            <h4 className="font-heading font-black text-3xl uppercase tracking-tighter">Impact</h4>
                            <p className="font-sans font-medium text-sm md:text-base mt-2 text-[#444]">Revolutionizing edge computing and physics-based motion control.</p>
                            <div className="self-end bg-[#1A1A1A] text-white font-sans font-bold py-1 px-4 rounded-full rotate-[5deg] mt-4 text-xs md:text-sm shadow-sm">
                                2024
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
}
